import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.WmBmIPw-.js";const h=JSON.parse('{"title":"粒子群优化（Particle Swarm Optimization, PSO）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/particle-swarm-optimization.md","filePath":"or-opt/particle-swarm-optimization.md","lastUpdated":1777183997000}'),e={name:"or-opt/particle-swarm-optimization.md"};function p(l,i,s,_,n,c){return t(),r("div",null,[...i[0]||(i[0]=[o('<h1 id="粒子群优化-particle-swarm-optimization-pso" tabindex="-1">粒子群优化（Particle Swarm Optimization, PSO） <a class="header-anchor" href="#粒子群优化-particle-swarm-optimization-pso" aria-label="Permalink to &quot;粒子群优化（Particle Swarm Optimization, PSO）&quot;">​</a></h1><p>粒子群优化将候选解表示为在搜索空间中的一群「粒子」：各粒子有位置与速度，在迭代中彼此参照个体历史最优与群体（或邻域）最优来更新速度，再移动位置。最初多用于连续实向量上的最小化/最大化，后亦有离散、约束与多目标变体。属群体式元启发式，见 <a href="./metaheuristics.html">元启发式总览</a>。</p><p><strong>适用</strong>：目标 f 在 ℝⁿ 或箱约束乘积空间上可求值、且梯度不可得或求梯度代价大时，常作黑箱近似优化；也见于神经网络权值初搜等（需与问题特化算子、边界与可行性处理一起设计）。</p><p><strong>核心</strong>：第 t 代第 i 个粒子的速度 v_i^t 由惯性项、指向自身历史最优 p_i 的项、及指向（全局或拓扑）群体最优 g 的项组成；再按 v 更新位置 x_i^t+1。系数（惯性 w、认知系数 c₁、社会系数 c₂ 及随机数）调节探索与利用。最小化时 p_i、g 用当前已知最小 f 对应位置。</p><hr><h2 id="算法-最小化、全局最优-pso-示意" tabindex="-1">算法（最小化、全局最优 PSO 示意） <a class="header-anchor" href="#算法-最小化、全局最优-pso-示意" aria-label="Permalink to &quot;算法（最小化、全局最优 PSO 示意）&quot;">​</a></h2><p>设目标 f(x) 在盒约束或 Rⁿ 上可计算；d 为维数。记第 i 个粒子的位置为 x_i，速度为 v_i；p_i 为 i 的个体历史最优位置，g 为全体中当前历史最优位置。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 粒子群优化 主循环（速度—位置、全局 g）</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>在可行域上随机或启发式设置各粒子的 x_i、v_i。评价各 f(x_i)。令 p_i ← x_i，g ← arg min_{i} f(x_i)（在粒子集合上取 f 最小者所对应位置；并列时任取一约定）。</p><h3 id="_2-每一代-外循环未终止前重复执行" tabindex="-1">2. 每一代（外循环未终止前重复执行） <a class="header-anchor" href="#_2-每一代-外循环未终止前重复执行" aria-label="Permalink to &quot;2. 每一代（外循环未终止前重复执行）&quot;">​</a></h3><p>对全体粒子下标 i 更新（i 的遍历顺序实现可定稿；单线程下无竞态；若并行更新 g 需规定读写规则）：</p><ul><li>速度更新：v_i ← w v_i + c₁ r₁ ⊙ (p_i − x_i) + c₂ r₂ ⊙ (g − x_i)。w 为惯性权重；c₁、c₂ 为非负常数；r₁、r₂ 为 [0,1] 上独立均匀随机向量，与 x_i 同维，⊙ 为逐分量相乘；g 为当前全体最优位置。</li><li>位置与边界：x_i ← x_i + v_i。若存在盒约束或域边界，对 x_i、v_i 做截断或反弹等，以保持可行或满足实现约定。</li><li>评价与极值：若 f(x_i) &lt; f(p_i)，令 p_i ← x_i；若 f(x_i) 产生新的群体最优，则更新 g。<br> 若仍未达最大代数/评价次数/时间/无改进等外终止条件，回到本步再次执行一代；否则进入下一步。</li></ul><h3 id="_3-输出" tabindex="-1">3. 输出 <a class="header-anchor" href="#_3-输出" aria-label="Permalink to &quot;3. 输出&quot;">​</a></h3><p>输出 g（或使 f 最小的 x 与记录）。</p></div><hr><h2 id="关键要素" tabindex="-1">关键要素 <a class="header-anchor" href="#关键要素" aria-label="Permalink to &quot;关键要素&quot;">​</a></h2><p><strong>参数 w、c₁、c₂</strong>：w&gt;1 易发散，过小则早熟；c₁ 大则个体历史牵引强，c₂ 大则向当前 g 聚集快。常结合压缩因子或随时间降 w。</p><p><strong>g 的拓扑</strong>：上框为全局 PSO，g 为全体一最优。大规模或防早熟时可改用环形、星形等邻域拓扑，g 由邻域内极值代替（局部 PSO/多种拓扑文献）。</p><p><strong>可行与边界</strong>：越界时常见做法包括把 x 投影回盒、将 v 置 0 或取反、惩罚不可行 f；需与问题一致并写进复现说明。</p><p><strong>离散/组合 PSO</strong>：位置与速度的运算需与编码一致（如排列用交换子、概率化更新）；与连续式同一套符号不再逐维相加时，本页不展开为另一套伪代码。</p>',14)])])}const d=a(e,[["render",p]]);export{h as __pageData,d as default};
